import { defineStore } from 'pinia'

// 定义RAG项目核心状态
export const useRagStore = defineStore('rag', {
  state: () => ({
    // 上传的文档列表（存储文档名称、解析后的文本块）
    documentList: [],
    // 问答历史（存储提问、回答、相关文本块）
    qaHistory: [],
    // 当前提问和回答（临时存储）
    currentQuestion: '',
    currentAnswer: '',
    // 相关文本块（RAG检索后存储）
    relatedTexts: []
  }),
  actions: {
    // 添加文档到列表
    addDocument(doc) {
      this.documentList.push(doc)
    },
    // 添加问答历史
    addQaHistory(question, answer, relatedTexts = []) {
      this.qaHistory.push({
        question,
        answer,
        relatedTexts,
        time: new Date().toLocaleString()
      })
    },
    // 清空问答历史
    clearQaHistory() {
      this.qaHistory = []
    }
  }
})
